<?php ao_license_ensure_v1888(); $products=db()->query('SELECT * FROM license_products ORDER BY name')->fetchAll(); $plans=db()->query('SELECT lp.*, p.name product_name FROM license_plans lp LEFT JOIN license_products p ON p.id=lp.product_id ORDER BY lp.id DESC')->fetchAll(); $licenses=db()->query('SELECT l.*, p.name product_name, lp.name plan_name FROM licenses l LEFT JOIN license_products p ON p.id=l.product_id LEFT JOIN license_plans lp ON lp.id=l.plan_id ORDER BY l.id DESC LIMIT 100')->fetchAll(); ?>
<div class="ao-card"><h2>Lisans Üret</h2><p>Offline-first imzalı lisans üretir. Ahost One'a ulaşılamasa bile ürün kendi içindeki <code>license.json</code> + <code>license.sig</code> + public key ile doğrulama yapar.</p><form method="post" action="<?= url('admin/license-center/license-generate') ?>"><?= csrf_field() ?><div class="ao-form-grid"><label>Ürün<select name="product_id"><option value="0">Plandan gelsin</option><?php foreach($products as $p): ?><option value="<?= (int)$p['id'] ?>"><?= e($p['name']) ?></option><?php endforeach; ?></select></label><label>Plan<select name="plan_id"><option value="0">Plansız</option><?php foreach($plans as $p): ?><option value="<?= (int)$p['id'] ?>"><?= e($p['product_name'].' - '.$p['name']) ?></option><?php endforeach; ?></select></label><label>Lisans Tipi<select name="license_type"><option value="subscription">Süreli</option><option value="lifetime">Ömür Boyu</option><option value="domain_lifetime">Domain Bazlı Ömür Boyu</option><option value="external">Harici Purchase Code</option></select></label><label>Müşteri ID<input type="number" name="customer_id" value="0"></label><label>Domain<input name="domain" placeholder="example.com"></label><label>Android Paket Adı / Uygulama ID<input name="package_name" placeholder="com.firma.uygulama"></label><label>Offline Cache Gün<input type="number" name="offline_grace_days" value="30"></label></div><button class="ao-btn">İmzalı Lisans Üret</button></form></div>
<div class="ao-card"><h3>Lisanslar</h3><table class="ao-table"><tr><th>ID</th><th>Lisans</th><th>Ürün</th><th>Tip</th><th>Domain</th><th>Paket</th><th>Durum</th><th>Bitiş</th></tr><?php foreach($licenses as $l): ?><tr><td><?= (int)$l['id'] ?></td><td><code><?= e($l['license_key']) ?></code></td><td><?= e($l['product_name'] ?: '-') ?></td><td><?= e($l['license_type'] ?? '-') ?></td><td><?= e($l['bound_domain'] ?: $l['domain']) ?></td><td><?= e($l['package_name'] ?? '-') ?></td><td><?= e($l['status']) ?></td><td><?= e($l['expires_at'] ?: 'Ömür boyu / süresiz') ?></td></tr><?php endforeach; ?></table></div>
